@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinel" class="infinite-scroll-sentinel">
            @if (_loading)
            {
                <div class="infinite-scroll-spinner" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    private ElementReference _sentinel;
    private IJSObjectReference? _module;
    private IJSObjectReference? _observer;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _selfRef;
    private bool _loading;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/infinite-scroll.js");

            _selfRef = DotNetObjectReference.Create(this);

            _observer = await _module.InvokeAsync<IJSObjectReference>(
                "createObserver", _sentinel, _selfRef);
        }
    }

    [JSInvokable]
    public async Task OnIntersecting()
    {
        if (_loading || !HasMore)
            return;

        _loading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        _loading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_observer is not null)
        {
            await _observer.InvokeVoidAsync("disconnect");
            await _observer.DisposeAsync();
        }

        if (_module is not null)
            await _module.DisposeAsync();

        _selfRef?.Dispose();
    }
}

export function createObserver(sentinel, dotNetRef) {
    const observer = new IntersectionObserver(entries => {
        if (entries.some(e => e.isIntersecting)) {
            dotNetRef.invokeMethodAsync('OnIntersecting');
        }
    }, {
        rootMargin: '0px 0px 200px 0px'
    });

    observer.observe(sentinel);
    return observer;
}

.infinite-scroll-container {
    overflow-y: auto;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem;
    min-height: 1px;
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 0.25rem solid currentColor;
    border-right-color: transparent;
    border-radius: 50%;
    animation: infinite-scroll-spin 0.75s linear infinite;
}

@keyframes infinite-scroll-spin {
    to { transform: rotate(360deg); }
}

